#!/usr/bin/env python

import os
import sys
import tarfile
import zipfile
import subprocess
import shutil
import time
from datetime import datetime

def validate_path(path):
    if not path:
        raise ValueError("Path cannot be empty")
    
    real_path = os.path.realpath(os.path.expanduser(path))
    
    if not os.path.exists(real_path):
        raise ValueError("Path does not exist: {}".format(real_path))
    
    if not os.path.isdir(real_path):
        raise ValueError("Path is not a directory: {}".format(real_path))
    
    return real_path

def validate_format(fmt):
    valid_formats = ['tar.gz', 'tar.bz2', 'zip', '7z']
    if fmt not in valid_formats:
        raise ValueError("Invalid format. Must be one of: {}".format(', '.join(valid_formats)))
    return fmt

def get_archive_name(directory, fmt):
    dir_name = os.path.basename(directory.rstrip(os.sep))
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    
    if fmt == 'tar.gz':
        ext = '.tar.gz'
    elif fmt == 'tar.bz2':
        ext = '.tar.bz2'
    elif fmt == 'zip':
        ext = '.zip'
    elif fmt == '7z':
        ext = '.7z'
    else:
        ext = '.tar.gz'
    
    return "{}_{}_backup{}".format(dir_name, timestamp, ext)

def create_tar_archive(directory, output_path, compression):
    mode_map = {
        'tar.gz': 'w:gz',
        'tar.bz2': 'w:bz2'
    }
    
    mode = mode_map.get(compression, 'w:gz')
    
    with tarfile.open(output_path, mode) as tar:
        tar.add(directory, arcname=os.path.basename(directory))
    
    return output_path

def create_zip_archive(directory, output_path):
    with zipfile.ZipFile(output_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
        for root, dirs, files in os.walk(directory):
            for file in files:
                file_path = os.path.join(root, file)
                arcname = os.path.relpath(file_path, os.path.dirname(directory))
                zipf.write(file_path, arcname)
    
    return output_path

def create_7z_archive(directory, output_path):
    seven_zip_paths = ['7z', '7za', '/usr/bin/7z', '/usr/bin/7za']
    seven_zip_cmd = None
    
    for cmd in seven_zip_paths:
        if shutil.which(cmd) or os.path.isfile(cmd):
            seven_zip_cmd = cmd
            break
    
    if not seven_zip_cmd:
        raise RuntimeError("7z command not found. Please install p7zip or p7zip-full package")
    
    parent_dir = os.path.dirname(directory)
    dir_name = os.path.basename(directory)
    
    cmd = [seven_zip_cmd, 'a', '-t7z', output_path, dir_name]
    
    try:
        process = subprocess.Popen(
            cmd,
            cwd=parent_dir,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE
        )
        stdout, stderr = process.communicate()
        
        if process.returncode != 0:
            raise RuntimeError("7z compression failed: {}".format(stderr.decode('utf-8', errors='ignore')))
        
        return output_path
    except OSError as e:
        raise RuntimeError("Failed to execute 7z: {}".format(str(e)))

def create_backup(directory, fmt, output_dir=None):
    directory = validate_path(directory)
    fmt = validate_format(fmt)
    
    if output_dir:
        output_dir = validate_path(output_dir)
    else:
        output_dir = os.getcwd()
    
    archive_name = get_archive_name(directory, fmt)
    output_path = os.path.join(output_dir, archive_name)
    
    print("Creating backup of: {}".format(directory))
    print("Format: {}".format(fmt))
    print("Output: {}".format(output_path))
    
    start_time = time.time()
    
    if fmt in ['tar.gz', 'tar.bz2']:
        result = create_tar_archive(directory, output_path, fmt)
    elif fmt == 'zip':
        result = create_zip_archive(directory, output_path)
    elif fmt == '7z':
        result = create_7z_archive(directory, output_path)
    else:
        raise ValueError("Unsupported format: {}".format(fmt))
    
    elapsed_time = time.time() - start_time
    
    if os.path.exists(result):
        file_size = os.path.getsize(result)
        size_mb = file_size / (1024.0 * 1024.0)
        print("Backup completed successfully!")
        print("Archive: {}".format(result))
        print("Size: {:.2f} MB".format(size_mb))
        print("Time: {:.2f} seconds".format(elapsed_time))
        return result
    else:
        raise RuntimeError("Backup failed: archive not created")

def main():
    if len(sys.argv) < 3:
        print("Usage: {} <directory_path> <format> [output_directory]".format(sys.argv[0]))
        print("Formats: tar.gz, tar.bz2, zip, 7z")
        sys.exit(1)
    
    directory = sys.argv[1]
    fmt = sys.argv[2]
    output_dir = sys.argv[3] if len(sys.argv) > 3 else None
    
    try:
        create_backup(directory, fmt, output_dir)
    except Exception as e:
        print("Error: {}".format(str(e)))
        sys.exit(1)

if __name__ == '__main__':
    main()